<body>
  <div class="container">
    <h1>Client-Side Journal Analyzer</h1>
    <div id="root"></div>
  </div>

  <!-- React + Babel (no build pipeline) -->
  <script crossorigin src="https://unpkg.com/react@18/umd/react.development.js"></script>
  <script crossorigin src="https://unpkg.com/react-dom@18/umd/react-dom.development.js"></script>
  <script src="https://unpkg.com/babel-standalone@6/babel.min.js"></script>

  <!-- PDF.js (for PDF text extraction) -->
  <script src="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.2.67/pdf.min.js"></script>

  <script type="text/babel">
    const { useEffect, useMemo, useState } = React;

    function round3(n) {
      return Math.round(n * 1000) / 1000;
    }

    function normalizeWhitespace(s) {
      return (s || "").replace(/\r\n/g, "\n").replace(/\t/g, " ");
    }

    function tokenizeWords(text) {
      // Words: sequences of letters/numbers incl apostrophes; keeps it simple and deterministic.
      const matches = (text || "").match(/[A-Za-z0-9']+/g);
      return matches ? matches : [];
    }

    function countRegexMatches(text, re) {
      if (!text) return 0;
      const m = text.match(re);
      return m ? m.length : 0;
    }

    function countKeyword(words, keywordLower) {
      let c = 0;
      for (const w of words) {
        if (w.toLowerCase() === keywordLower) c++;
      }
      return c;
    }

    function firstSentence(text) {
      const t = (text || "").trim();
      if (!t) return "";
      // First sentence split on . ! ? followed by whitespace/newline/end.
      const m = t.match(/^[\s\S]*?[.!?](?:\s|$)/);
      if (m) return m[0].trim();
      // Fallback: first non-empty line
      const line = t.split(/\n+/).map(s => s.trim()).find(Boolean);
      return (line || t).trim();
    }

    function summarizeFromMarkdown(mdText) {
      const text = normalizeWhitespace(mdText);
      const lines = text.split("\n");

      const sections = [];
      let current = null;
      let buffer = [];

      function flush() {
        if (!current) return;
        const body = buffer.join("\n").trim();
        const summary = firstSentence(body.replace(/\n+/g, "\n"));
        sections.push({ title: current, summary: summary || "" });
      }

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];
        const headerMatch = line.match(/^\s*#+\s+(.*)\s*$/);
        if (headerMatch) {
          flush();
          current = headerMatch[1].trim() || "(Untitled)";
          buffer = [];
        } else {
          if (current) buffer.push(line);
        }
      }
      flush();

      // If no markdown headers exist, make a single section.
      if (sections.length === 0) {
        const summary = firstSentence(text);
        return [{ title: "Document", summary: summary || "" }];
      }
      return sections;
    }

    function recoverHeadingsFromPdfText(rawText) {
      // Heuristic: treat short ALL-CAPS lines or lines ending with ':' as headings.
      const text = normalizeWhitespace(rawText);
      const lines = text.split(/\n+/).map(l => l.trim()).filter(Boolean);

      const out = [];
      let currentTitle = null;
      let buffer = [];

      function isLikelyHeading(line) {
        if (!line) return false;
        if (line.length > 80) return false;
        const hasLetters = /[A-Za-z]/.test(line);
        if (!hasLetters) return false;
        const lettersOnly = line.replace(/[^A-Za-z]/g, "");
        const upperRatio = lettersOnly ? (lettersOnly.replace(/[^A-Z]/g, "").length / lettersOnly.length) : 0;
        if (upperRatio >= 0.85 && lettersOnly.length >= 4) return true;
        if (/:$/.test(line) && line.length <= 80) return true;
        return false;
      }

      function flush() {
        if (!currentTitle) return;
        const body = buffer.join("\n").trim();
        out.push({ title: currentTitle, body });
      }

      for (const line of lines) {
        if (isLikelyHeading(line)) {
          flush();
          currentTitle = line.replace(/:$/, "").trim();
          buffer = [];
        } else {
          if (!currentTitle) {
            currentTitle = "Document";
          }
          buffer.push(line);
        }
      }
      flush();

      // Convert to {title, summary}
      const summaries = out.map(s => ({ title: s.title, summary: firstSentence(s.body) || "" }));
      return summaries.length ? summaries : [{ title: "Document", summary: firstSentence(text) || "" }];
    }

    async function extractTextFromPdf(arrayBuffer) {
      if (!window.pdfjsLib) throw new Error("pdf.js failed to load");
      // Configure worker
      window.pdfjsLib.GlobalWorkerOptions.workerSrc = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.2.67/pdf.worker.min.js";

      const loadingTask = window.pdfjsLib.getDocument({ data: arrayBuffer });
      const pdf = await loadingTask.promise;

      let fullText = "";
      for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
        const page = await pdf.getPage(pageNum);
        const content = await page.getTextContent();
        const strings = content.items.map(it => (it.str || "").trim()).filter(Boolean);
        // Join with spaces; add a newline per page to help heading recovery.
        fullText += strings.join(" ") + "\n";
      }
      return fullText;
    }

    function analyzeText({ fileType, text }) {
      const raw = normalizeWhitespace(text || "");

      const citations = countRegexMatches(raw, /\[(\d+)\]/g);

      const words = tokenizeWords(raw);
      const totalWords = words.length;

      const quantumCount = countKeyword(words, "quantum");
      const entCount = countKeyword(words, "entanglement");

      const keywordDensity = {
        quantum: {
          count: quantumCount,
          density: round3(totalWords ? quantumCount / totalWords : 0)
        },
        entanglement: {
          count: entCount,
          density: round3(totalWords ? entCount / totalWords : 0)
        }
      };

      let sectionSummaries = [];
      if (fileType === "markdown") {
        sectionSummaries = summarizeFromMarkdown(raw);
      } else if (fileType === "pdf") {
        sectionSummaries = recoverHeadingsFromPdfText(raw);
      } else {
        sectionSummaries = [{ title: "Document", summary: firstSentence(raw) || "" }];
      }

      return {
        fileType,
        citations,
        totalWords,
        keywordDensity,
        sectionSummaries
      };
    }

    function App() {
      const [status, setStatus] = useState("No file loaded.");
      const [analysis, setAnalysis] = useState({
        fileType: null,
        citations: 0,
        totalWords: 0,
        keywordDensity: {
          quantum: { count: 0, density: 0 },
          entanglement: { count: 0, density: 0 }
        },
        sectionSummaries: []
      });

      async function handleFileChange(e) {
        const file = e.target.files && e.target.files[0];
        if (!file) return;

        const name = file.name || "";
        const lower = name.toLowerCase();
        const isMd = lower.endsWith(".md") || lower.endsWith(".markdown");
        const isPdf = lower.endsWith(".pdf") || file.type === "application/pdf";

        setStatus(`Loading ${name}...`);

        try {
          if (isMd) {
            const text = await file.text();
            const next = analyzeText({ fileType: "markdown", text });
            setAnalysis(next);
            setStatus(`Loaded ${name} (Markdown).`);
          } else if (isPdf) {
            const buf = await file.arrayBuffer();
            const pdfText = await extractTextFromPdf(buf);
            const next = analyzeText({ fileType: "pdf", text: pdfText });
            setAnalysis(next);
            setStatus(`Loaded ${name} (PDF).`);
          } else {
            // Still attempt to read as text for robustness.
            const text = await file.text();
            const next = analyzeText({ fileType: "unknown", text });
            setAnalysis(next);
            setStatus(`Loaded ${name} (unknown type; treated as text).`);
          }
        } catch (err) {
          console.error(err);
          setStatus(`Error: ${err && err.message ? err.message : String(err)}`);
        }
      }

      const analysisJson = useMemo(() => {
        // Ensure stable, valid JSON. (No functions, undefined, etc.)
        return JSON.stringify(analysis, null, 2);
      }, [analysis]);

      return (
        <div>
          <div className="panel">
            <label htmlFor="file">Upload journal file (.md, .markdown, .pdf)</label>
            <input
              id="file"
              type="file"
              accept=".md,.markdown,.pdf,application/pdf,text/markdown"
              onChange={handleFileChange}
            />
            <div className="status"><span className="muted">Status:</span> {status}</div>
          </div>

          <div className="row">
            <div className="panel col">
              <h2 style={{ marginTop: 0 }}>Citation Frequency</h2>
              <div className="kpi">{analysis.citations}</div>
              <div className="kpi-sub">Bracket citations like <code>[1]</code>, <code>[42]</code></div>
            </div>

            <div className="panel col">
              <h2 style={{ marginTop: 0 }}>Keyword Density</h2>
              <div>
                <div><strong>quantum</strong>: {analysis.keywordDensity.quantum.count} (density {analysis.keywordDensity.quantum.density})</div>
                <div><strong>entanglement</strong>: {analysis.keywordDensity.entanglement.count} (density {analysis.keywordDensity.entanglement.density})</div>
                <div className="kpi-sub">Density = count / totalWords (rounded to 3 decimals). Total words: {analysis.totalWords}</div>
              </div>
            </div>
          </div>

          <div className="panel">
            <h2 style={{ marginTop: 0 }}>Section Summaries</h2>
            {analysis.sectionSummaries && analysis.sectionSummaries.length ? (
              <div>
                {analysis.sectionSummaries.map((s, idx) => (
                  <div className="summary-item" key={idx}>
                    <div className="summary-title">{s.title}</div>
                    <div>{s.summary || <span className="muted">(No summary found)</span>}</div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="muted">No sections detected yet.</div>
            )}
          </div>

          <div className="panel">
            <h3 style={{ marginTop: 0 }}>Machine-readable analysis</h3>
            {/* CRITICAL FOR TESTS */}
            <pre id="analysis-output">{analysisJson}</pre>
          </div>
        </div>
      );
    }

    const root = ReactDOM.createRoot(document.getElementById('root'));
    root.render(<App />);
  </script>
</body>
</html>
